// The drug-allergy class / cross-reactivity dataset, loaded onto the curated-dataset
// framework (issue #1029). Copies the ototoxic.ts shape: import the envelope JSON
// (generated by scripts/gen-drug-allergy.ts), validate it once with loadDataset(), and
// expose the CLASS entries (drug-class concepts, matched by RxCUI ingredient + synonym)
// plus the cross-class reactivity rules (meta) the cross-check consumes. Identity is
// the class `key` token (fieldStrategy "key"). The registry lists this for the linter;
// lib/drug-allergy.ts is the DOMAIN cross-check. Pure — no DB, no network.

import rawDrugAllergy from "./data/drug-allergy.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type {
  DrugAllergyClassEntry,
  DrugAllergyCrossRule,
  DrugAllergyMeta,
} from "@/scripts/gen-drug-allergy";

export type {
  DrugAllergyClassEntry,
  DrugAllergyCrossRule,
  DrugAllergyMeta,
} from "@/scripts/gen-drug-allergy";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const drugAllergyDataset = loadDataset<
  DrugAllergyClassEntry,
  DrugAllergyMeta
>(rawDrugAllergy);

// Identity strategy: the class `key` token, case-folded. For the linter.
export const drugAllergyKeyStrategy = fieldStrategy("key");

// The drug-class entries (concepts) the cross-check resolves allergens + meds to.
export const DRUG_ALLERGY_CLASSES: DrugAllergyClassEntry[] =
  drugAllergyDataset.entries;

// The documented cross-class reactivity rules (unordered pairs of class keys).
export const DRUG_ALLERGY_CROSS_RULES: DrugAllergyCrossRule[] = (
  drugAllergyDataset.meta as DrugAllergyMeta
).crossReactivity;
